以下是使用C++编程语言生成介于-1到1之间的2D Halton序列的示例代码：

```cpp
#include <iostream>
#include <cmath>

// Function to generate Halton sequence for a given dimension and point count
void generateHaltonSequence(int dimensions, int points, double* sequence) {
    for (int i = 0; i < points; i++) {
        int index = i + 1;
        double x = 0.0, y = 0.0;
        double f = 1.0;

        for (int j = 0; j < dimensions; j++) {
            int base = j % 2 == 0 ? 2 : 3;  // Use base 2 for even dimensions, base 3 for odd dimensions
            double value = 0.0;
            double f_inv = 1.0 / base;

            while (index > 0) {
                value += f_inv * (index % base);
                index /= base;
                f_inv /= base;
            }

            if (j % 2 == 0) {
                x = 2.0 * value - 1.0;
            }
            else {
                y = 2.0 * value - 1.0;
            }
        }

        sequence[2 * i] = x;
        sequence[2 * i + 1] = y;
    }
}

int main() {
    const int dimensions = 2;
    const int points = 15;

    double sequence[2 * points];

    generateHaltonSequence(dimensions, points, sequence);

    for (int i = 0; i < points; i++) {
        std::cout << "[" << sequence[2 * i] << ", " << sequence[2 * i + 1] << "]" << std::endl;
    }

    return 0;
}
```

